#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int start;
    int end;
    int cost;
} interval;

// Comparison function to sort intervals based on the starting time
int compare(const void *a, const void *b) {
    interval *intervalA = (interval *)a;
    interval *intervalB = (interval *)b;
    return intervalA->start - intervalB->start;
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n;
        scanf("%d", &n);

        interval a[n];
        int dp[n];
        for (int i = 0; i < n; i++) {
            scanf("%d %d %d", &a[i].start, &a[i].end, &a[i].cost);
        }

        // Sort intervals based on the starting time
        qsort(a, n, sizeof(interval), compare);

        dp[0] = a[0].cost;
        int ans = dp[0];

        for (int i = 1; i < n; i++) {
            dp[i] = a[i].cost;
            for (int j = 0; j < i; j++) {
                if (a[j].end <= a[i].start) {
                    dp[i] = dp[i] > (dp[j] + a[i].cost) ? dp[i] : (dp[j] + a[i].cost);
                }
            }
            ans = ans > dp[i] ? ans : dp[i];
        }

        printf("%d\n", ans);
    }

    return 0;
}

