import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();

        while (t-- > 0) {
            int n = sc.nextInt();
            int[][] a = new int[n][3]; // s[i], e[i], c[i]
            int[] dp = new int[n];

            for (int i = 0; i < n; i++) {
                a[i][0] = sc.nextInt(); // s[i]
                a[i][1] = sc.nextInt(); // e[i]
                a[i][2] = sc.nextInt(); // c[i]
            }

            // Sort the array based on the starting points (s[i])
            Arrays.sort(a, Comparator.comparingInt(arr -> arr[0]));

            dp[0] = a[0][2]; // c[0]
            int ans = dp[0]; // c[0]

            // Dynamic programming to find the maximum sum of non-overlapping intervals
            for (int i = 1; i < n; i++) {
                dp[i] = a[i][2]; // c[i]
                for (int j = 0; j < i; j++) {
                    if (a[j][1] <= a[i][0]) { // if e[j] <= s[i]
                        dp[i] = Math.max(dp[i], dp[j] + a[i][2]); // dp[j] + c[i]
                    }
                }
                ans = Math.max(ans, dp[i]);
            }
            System.out.println(ans);
        }
        sc.close();
    }
}

