const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let inputLines = [];
let currentLine = 0;

rl.on('line', (line) => {
    inputLines.push(line);
});

rl.on('close', () => {
    main();
});

function readInt() {
    return parseInt(inputLines[currentLine++]);
}

function readArray() {
    return inputLines[currentLine++].split(' ').map(Number);
}

function main() {
    let t = readInt();

    while (t-- > 0) {
        let n = readInt();
        let a = [];

        for (let i = 0; i < n; i++) {
            let arr = readArray(); // reading s[i], e[i], c[i]
            a.push(arr);
        }

        // Sort the array based on the starting points (s[i])
        a.sort((x, y) => x[0] - y[0]);

        let dp = new Array(n).fill(0);

        dp[0] = a[0][2]; // c[0]
        let ans = dp[0]; // c[0]

        // Dynamic programming to find the maximum sum of non-overlapping intervals
        for (let i = 1; i < n; i++) {
            dp[i] = a[i][2]; // c[i]
            for (let j = 0; j < i; j++) {
                if (a[j][1] <= a[i][0]) { // if e[j] <= s[i]
                    dp[i] = Math.max(dp[i], dp[j] + a[i][2]); // dp[j] + c[i]
                }
            }
            ans = Math.max(ans, dp[i]);
        }
        console.log(ans);
    }
}
